import { utils, write } from 'xlsx';
import { Offer, TestCase, TestPlanSummary } from './types';

export class ExcelGenerator {
  static generateWorkbook(
    offers: Offer[],
    positiveTests: TestCase[],
    negativeTests: TestCase[],
    summary: TestPlanSummary
  ): Buffer {
    const workbook = utils.book_new();

    // Combine all tests
    const allTests = [...positiveTests, ...negativeTests];

    // Create header row
    const headers = [
      'Test ID',
      'Test Type',
      'Offer ID',
      'Offer Name',
      'Description',
      'Customer Status',
      'Customer Type',
      'Customer Tags',
      'Sales Channel',
      'Division',
      'Tenure Days',
      'Existing Services',
      'Speed Tier',
      'Expected Result',
    ];

    // Create data rows
    const data = [headers];
    allTests.forEach((test) => {
      data.push([
        test.test_id,
        test.test_type,
        test.offer_id,
        test.offer_name,
        test.description || '',
        test.customer_status || '',
        test.customer_type || '',
        test.customer_tags || '',
        test.sales_channel || '',
        test.division || '',
        test.tenure_days || '',
        test.existing_services || '',
        test.speed_tier || '',
        test.expected_result || '',
      ]);
    });

    // Create sheet
    const sheet = utils.aoa_to_sheet(data);

    // Apply styling
    const range = utils.decode_range(sheet['!ref'] || 'A1');

    for (let R = range.s.r; R <= range.e.r; ++R) {
      for (let C = range.s.c; C <= range.e.c; ++C) {
        const cellAddress = utils.encode_col(C) + (R + 1);
        if (!sheet[cellAddress]) continue;

        const cell = sheet[cellAddress];

        if (R === 0) {
          // Header row - dark blue background, white text, bold
          cell.fill = { patternType: 'solid', fgColor: { rgb: 'FF1F4E78' } };
          cell.font = { bold: true, color: { rgb: 'FFFFFFFF' } };
        } else {
          // Get test type from column B (index 1)
          const testTypeCell = sheet[utils.encode_col(1) + (R + 1)];
          const testType = testTypeCell?.v;

          if (testType === 'Positive') {
            // Green background for positive tests
            cell.fill = { patternType: 'solid', fgColor: { rgb: 'FFE2EFD9' } };
          } else if (testType === 'Negative') {
            // Red background for negative tests
            cell.fill = { patternType: 'solid', fgColor: { rgb: 'FFFCE4D6' } };
          }
        }
      }
    }

    // Set column widths
    const colWidths = [12, 12, 15, 25, 30, 18, 15, 18, 18, 20, 15, 18, 12, 18];
    sheet['!cols'] = colWidths.map((w) => ({ wch: w }));

    // Freeze header row
    sheet['!freeze'] = { xSplit: 0, ySplit: 1 };

    // Add sheet to workbook
    utils.book_append_sheet(workbook, sheet, 'All Tests');

    // Write and return buffer
    const wbout = write(workbook, { bookType: 'xlsx', type: 'buffer' });
    return wbout;
  }

  private static formatTestData(tests: TestCase[]): string[][] {
    const data = [
      [
        'Test ID',
        'Test Type',
        'Offer ID',
        'Offer Name',
        'Description',
        'Customer Status',
        'Customer Type',
        'Customer Tags',
        'Sales Channel',
        'Division',
        'Tenure Days',
        'Existing Services',
        'Speed Tier',
        'Expected Result',
      ],
    ];

    tests.forEach((test) => {
      data.push([
        test.test_id,
        test.test_type,
        test.offer_id,
        test.offer_name,
        test.description || '',
        test.customer_status || '',
        test.customer_type || '',
        test.customer_tags || '',
        test.sales_channel || '',
        test.division || '',
        test.tenure_days || '',
        test.existing_services || '',
        test.speed_tier || '',
        test.expected_result || '',
      ]);
    });

    return data;
  }

  static formatTestDataWithColors(tests: TestCase[]): string[][] {
    return this.formatTestData(tests);
  }
}
